module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    reg [3:0] shift_count;

    always @(*) begin
        partial_product = 16'b0;
        shift_count = 4'b0;

        for (shift_count = 0; shift_count < 8; shift_count = shift_count + 1) begin
            if (B[shift_count]) begin
                partial_product = partial_product + (A << shift_count);
            end
        end

        product = partial_product;
    end
endmodule
